

# class Solution:
#     def maximumRobots(self, chargeTimes: list[int], runningCosts: list[int], budget: int) -> int:
#         n = len(chargeTimes)
#         # 考虑外层就是从1~n, 这是表示个数
#         for i in range(1, n+1):
#             # 然后需要设计前缀和, 需要有一个列表来存储这个前缀
#             ls = []
#             # 开始计算前缀和
#             for j in range(0, n-i+1):
#                 # 使用滑动时间窗口
#                 cur_charge = chargeTimes[j:j+i]
#                 cur_running = runningCosts[j:j+i]
#                 cur_ls_max = max(cur_charge)
#                 cur_ls_sum = sum(cur_running)
#                 ls.append(cur_ls_max + i * cur_ls_sum)
#             # print(ls)
#             # 直接取最小值吧
#             cur_i = min(ls)
#             if cur_i < budget:
#                 ans = i
#             else:
#                 break
#         return ans

from collections import deque

class Solution:
    def maximumRobots(self, chargeTimes: list[int], runningCosts: list[int], budget: int) -> int:
        res, n, runningCostSum = 0, len(chargeTimes), 0
        q, j = deque(), 0
        for i in range(n):
            runningCostSum += runningCosts[i]
            while q and chargeTimes[q[-1]] <= chargeTimes[i]:
                q.pop()
            q.append(i)
            while j <= i and (i - j + 1) * runningCostSum + chargeTimes[q[0]] > budget:
                if q and q[0] == j:
                    q.popleft()
                runningCostSum -= runningCosts[j]
                j += 1
            res = max(res, i - j + 1)
        return res


